import { mkdir, readFile, writeFile } from "node:fs/promises";
import path from "node:path";

export interface RankUser {
  userId: string;
  xp: number;
  level: number;
  messageCount: number;
  lastMessageAt: number;
  lastXpAt: number;
}

export interface RankStore {
  version: number;
  guilds: Record<string, Record<string, RankUser>>;
}

const DATA_DIR = path.join(process.cwd(), "data", "rankxp");
const DATA_FILE = path.join(DATA_DIR, "rankxp.json");

const STORE_VERSION = 1;

function now(): number {
  return Date.now();
}

function levelToTotalXp(level: number): number {
  // curva simples e estável
  // lvl 1 => 100, lvl 10 => 5500 (aprox)
  return Math.floor(50 * level * level + 50 * level);
}

function totalXpToLevel(totalXp: number): number {
  // resolve pela fórmula inversa aproximada e corrige por ajuste
  // totalXp ≈ 50L^2 + 50L
  // 50L^2 + 50L - totalXp = 0
  const a = 50;
  const b = 50;
  const c = -Math.max(0, totalXp);
  const disc = b * b - 4 * a * c;
  const approx = Math.floor((-b + Math.sqrt(Math.max(0, disc))) / (2 * a));
  let L = Math.max(0, approx);
  while (levelToTotalXp(L + 1) <= totalXp) L++;
  while (levelToTotalXp(L) > totalXp) L--;
  return L;
}

export function xpToNextLevel(totalXp: number): { level: number; cur: number; nextAt: number; remaining: number } {
  const level = totalXpToLevel(totalXp);
  const nextAt = levelToTotalXp(level + 1);
  return { level, cur: totalXp, nextAt, remaining: Math.max(0, nextAt - totalXp) };
}

async function loadStore(): Promise<RankStore> {
  try {
    const raw = await readFile(DATA_FILE, "utf8");
    const parsed = JSON.parse(raw) as RankStore;
    if (!parsed || typeof parsed !== "object") throw new Error("invalid store");
    if (!parsed.guilds) parsed.guilds = {};
    if (!parsed.version) parsed.version = STORE_VERSION;
    return parsed;
  } catch {
    return { version: STORE_VERSION, guilds: {} };
  }
}

async function saveStore(store: RankStore): Promise<void> {
  await mkdir(DATA_DIR, { recursive: true });
  await writeFile(DATA_FILE, JSON.stringify(store, null, 2), "utf8");
}

function ensureUser(store: RankStore, guildId: string, userId: string): RankUser {
  store.guilds[guildId] ??= {};
  store.guilds[guildId][userId] ??= {
    userId,
    xp: 0,
    level: 0,
    messageCount: 0,
    lastMessageAt: 0,
    lastXpAt: 0,
  };
  return store.guilds[guildId][userId]!;
}

export interface AwardResult {
  before: RankUser;
  after: RankUser;
  leveledUp: boolean;
  newLevel: number;
  xpAdded: number;
}

export async function awardXp(
  guildId: string,
  userId: string,
  amount: number,
): Promise<AwardResult> {
  const store = await loadStore();
  const u = ensureUser(store, guildId, userId);

  const before: RankUser = { ...u };

  u.xp = Math.max(0, u.xp + Math.max(0, Math.floor(amount)));
  const newLevel = totalXpToLevel(u.xp);
  const leveledUp = newLevel > u.level;
  u.level = newLevel;

  u.lastXpAt = now();

  await saveStore(store);

  return {
    before,
    after: { ...u },
    leveledUp,
    newLevel,
    xpAdded: amount,
  };
}

